SELECT id, share_uuid, space_id, creator_user_id, share_type, title, access_code_hash, allow_preview, allow_download,
       max_access_count, current_access_count, expired_at, status, revoked_at, created_at, updated_at
FROM shares
WHERE creator_user_id = #{creatorUserId}
ORDER BY created_at DESC, id DESC
LIMIT #{offset}, #{pageSize}
